// Test Munter formula with negative values
function calculateMunterTime\(distanceKm, elevationGainM, elevationLossM\) {
  if \(distanceKm === 0 && elevationGainM === 0 && elevationLossM === 0\) return 0;
  const tHoriz = \(distanceKm / 4\) * 60;
  const tVertGain = \(elevationGainM / 400\) * 60;
  const tVertLoss = \(elevationLossM / 800\) * 60;
  const tVert = Math.max\(tVertGain, tVertLoss\);
  return Math.max\(tHoriz, tVert\) + 0.5 * Math.min\(tHoriz, tVert\);
}

// What happens with negative elevation values
console.log\('Negative gain\(-100\):', calculateMunterTime\(1, -100, 0\)\);
console.log\('Negative loss\(0, -100\):', calculateMunterTime\(1, 0, -100\)\);
console.log\('Negative distance:', calculateMunterTime\(-1, 100, 0\)\);
console.log\('NaN distance:', calculateMunterTime\(NaN, 100, 0\)\);
console.log\('Very large values:', calculateMunterTime\(1000, 50000, 0\)\);

// Slope with 0 distance
function calculateSlope\(distanceKm, elevationGainM, elevationLossM\) {
  if \(distanceKm === 0\) return 0;
  const netElevation = Math.abs\(elevationGainM - elevationLossM\);
  return \(netElevation / \(distanceKm * 1000\)\) * 100;
}

// Equal gain and loss produces 0 slope \(not representative\)
console.log\('Slope with equal gain/loss \(500/500\):', calculateSlope\(2, 500, 500\)\);
console.log\('Slope with only gain 500 over 2km:', calculateSlope\(2, 500, 0\)\);
")

